/**
 * Compute 7/14/28-day GSC clicks/impressions/position deltas for a changeset.
 * Baseline = same window length BEFORE applied_at. Post = same window AFTER.
 * Idempotent via UNIQUE(changeset_id, window_days).
 */
export const measureLift = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((i) =>
    orgScoped.extend({ changesetId: z.string().uuid() }).parse(i),
  )
  .handler(async ({ data, context }) => {
    const supabase = context.supabase as SB;
    await assertMember(supabase, context.userId, data.organizationId);
    const { data: cs, error: csErr } = await supabase
      .from("content_changesets")
      .select("id, site_id, post_id, wp_post_id, applied_at, organization_id")
      .eq("id", data.changesetId)
      .eq("organization_id", data.organizationId)
      .single();
    if (csErr || !cs) throw new Error("Changeset not found");

    // Resolve URL from wordpress_posts if available
    let url: string | null = null;
    if (cs.post_id) {
      const { data: post } = await supabase
        .from("wordpress_posts")
        .select("url")
        .eq("id", cs.post_id)
        .maybeSingle();
      url = post?.url ?? null;
    }
    if (!url) return { measured: 0, note: "no URL on changeset" };

    const appliedAt = new Date(cs.applied_at);
    const results: Array<{ window_days: number }> = [];
    for (const win of [7, 14, 28]) {
      const baselineStart = new Date(appliedAt.getTime() - win * 86400000);
      const postEnd = new Date(appliedAt.getTime() + win * 86400000);
      const { data: rows } = await supabase
        .from("search_console_daily")
        .select("date, clicks, impressions, position")
        .eq("organization_id", data.organizationId)
        .eq("site_id", cs.site_id)
        .eq("page", url)
        .gte("date", baselineStart.toISOString().slice(0, 10))
        .lte("date", postEnd.toISOString().slice(0, 10));
      if (!rows || rows.length === 0) continue;
      let bC = 0, bI = 0, bPsum = 0, bPn = 0;
      let pC = 0, pI = 0, pPsum = 0, pPn = 0;
      for (const r of rows as Array<{
        date: string;
        clicks: number;
        impressions: number;
        position: number | null;
      }>) {
        const d = new Date(r.date);
        if (d < appliedAt) {
          bC += r.clicks; bI += r.impressions;
          if (r.position != null) { bPsum += Number(r.position); bPn++; }
        } else {
          pC += r.clicks; pI += r.impressions;
          if (r.position != null) { pPsum += Number(r.position); pPn++; }
        }
      }
      const bP = bPn ? bPsum / bPn : null;
      const pP = pPn ? pPsum / pPn : null;
      await supabase
        .from("lift_measurements")
        .upsert(
          {
            organization_id: data.organizationId,
            site_id: cs.site_id,
            changeset_id: cs.id,
            window_days: win,
            baseline_clicks: bC,
            baseline_impressions: bI,
            baseline_position: bP,
            post_clicks: pC,
            post_impressions: pI,
            post_position: pP,
            clicks_delta: pC - bC,
            impressions_delta: pI - bI,
            position_delta: bP != null && pP != null ? bP - pP : null,
          },
          { onConflict: "changeset_id,window_days" },
        );
      results.push({ window_days: win });
    }
    return { measured: results.length };
  });

export const listLiftSummary = createServerFn({ method: "POST" })
  .middleware([requireSupabaseAuth])
  .inputValidator((i) => orgScoped.parse(i))
  .handler(async ({ data, context }) => {
    const supabase = context.supabase as SB;
    await assertMember(supabase, context.userId, data.organizationId);
    const { data: rows, error } = await supabase
      .from("lift_measurements")
      .select("changeset_id, window_days, clicks_delta, impressions_delta, position_delta")
      .eq("organization_id", data.organizationId)
      .order("measured_at", { ascending: false })
      .limit(500);
    if (error) throw error;
    return { measurements: rows ?? [] };
  });